-- Region II (Cagayan Valley): Cagayan, Batanes, Isabela, Nueva Vizcaya, Quirino
-- BIR RDO 13(Cagayan+Batanes, split),14(Nueva Vizcaya),15(Isabela),16(Quirino). Newest-DO-year-wins per LGU.
START TRANSACTION;
DELETE FROM zonal_values WHERE province IN ('CAGAYAN','BATANES','NUEVA VIZCAYA','ISABELA','QUIRINO');
COMMIT;
